/* atanh, n = 4, r = 26: 4 levels, widths [3, 2, 2, 1] */
static void
_fixed_log1p_series_4(nn_ptr res, nn_srcptr x)
{
    ulong z[4], V[4], T[4], P[4], Z[2];
    ulong v, w1, w0, h, l;
    slong i;

    (void) v; (void) w1; (void) w0; (void) h; (void) l;
    (void) i; (void) Z; (void) V; (void) T; (void) P;

    flint_mpn_sqrhigh(z, x, 4);

    v = UWORD(0x1c71c71c71c71c71);

    /* V_2 = c + z V_3   (2 x 1 limbs) */
    _fixed_mulhi_2x1(&h, &l, z[3], z[2], v);
    add_ssaaaa(w1, w0, UWORD(0x2492492492492492), UWORD(0x4924924924924924), h, l);

    /* V_1 = c + z V_2   (2 x 2 limbs) */
    _fixed_mulhi_2x2_sloppy(&h, &l, z[3], z[2], w1, w0);
    add_ssaaaa(w1, w0, UWORD(0x3333333333333333), UWORD(0x3333333333333333), h, l);

    /* V_0 = c + z V_1   (3 x 2 limbs) */
    P[0] = UWORD(0);
    P[1] = w0; P[2] = w1;
    flint_mpn_mulhigh_n(T, z + 1, P, 3);
    P[0] = UWORD(0x5555555555555555);
    P[1] = UWORD(0x5555555555555555);
    P[2] = UWORD(0x5555555555555555);
    NN_ADD_3(V, P, T);

    /* atanh = x + x^3 V_0 */
    P[0] = UWORD(0);
    P[1] = V[0];
    P[2] = V[1];
    P[3] = V[2];
    flint_mpn_mulhigh_n(T, z, x, 4);
    flint_mpn_mulhigh_n(V, T, P, 4);
    NN_ADD_4(res, x, V);
}

void
fixed_log1p_opt_4(nn_ptr res, nn_srcptr x)
{
    const int r = 26;
    ulong d0, d1, d2, d3;
    ulong p0, p1, p2, p3;
    ulong a0, a1, a2, a3;
    ulong e0, e1, e2, e3;
    ulong v0, v1, v2, v3;
    ulong bw, m, h, lt;
    ulong S[5], nd[8], t[4], y[4];
    slong i, nc;


    nn_srcptr tab;
    tab = _fixed_exp_logs_tab(4, r, &nc);

    d0 = x[0];
    d1 = x[1];
    d2 = x[2];
    d3 = x[3];
    p0 = 0;
    p1 = 0;
    p2 = 0;
    p3 = 0;
    a0 = 0;
    a1 = 0;
    a2 = 0;
    a3 = 0;

#define LP(ii) (tab + (ii) * nc + (nc - 4))

    /* window 0 */
    {
        nn_srcptr Lp;

        /* boundary step i = 1 */
        Lp = LP(1);
        v0 = MPN_RIGHT_SHIFT_LOW(p1, p0, 1);
        v1 = MPN_RIGHT_SHIFT_LOW(p2, p1, 1);
        v2 = MPN_RIGHT_SHIFT_LOW(p3, p2, 1);
        v3 = MPN_RIGHT_SHIFT_LOW(UWORD(1), p3, 1);
        sub_dddddmmmmmsssss(bw, e3, e2, e1, e0,
            UWORD(0), d3, d2, d1, d0,
            UWORD(0), v3, v2, v1, v0);
        m = ~bw;                /* accept iff no borrow */
        d0 = (d0 & bw) | (e0 & m);
        d1 = (d1 & bw) | (e1 & m);
        d2 = (d2 & bw) | (e2 & m);
        d3 = (d3 & bw) | (e3 & m);
        add_ssssaaaaaaaa(p3, p2, p1, p0,
            p3, p2, p1, p0,
            (v3) & m, (v2) & m, (v1) & m, (v0) & m);
        add_ssssaaaaaaaa(a3, a2, a1, a0,
            a3, a2, a1, a0,
            Lp[3] & m, Lp[2] & m, Lp[1] & m, Lp[0] & m);

        h = d3;

        for (i = 2; i <= 26; i++)
        {
            int b = (int) (i - 0);

            lt = MPN_RIGHT_SHIFT_LOW(UWORD(1), p3, b);
            if (h < lt)
                continue;    /* certain reject */

            Lp = LP(i);
            v0 = MPN_RIGHT_SHIFT_LOW(p1, p0, b);
            v1 = MPN_RIGHT_SHIFT_LOW(p2, p1, b);
            v2 = MPN_RIGHT_SHIFT_LOW(p3, p2, b);
            v3 = lt;
            sub_dddddmmmmmsssss(bw, e3, e2, e1, e0,
                UWORD(0), d3, d2, d1, d0,
                UWORD(0), v3, v2, v1, v0);
            m = ~bw;                /* accept iff no borrow */
            d0 = (d0 & bw) | (e0 & m);
            d1 = (d1 & bw) | (e1 & m);
            d2 = (d2 & bw) | (e2 & m);
            d3 = (d3 & bw) | (e3 & m);
            add_ssssaaaaaaaa(p3, p2, p1, p0,
                p3, p2, p1, p0,
                (v3) & m, (v2) & m, (v1) & m, (v0) & m);
            add_ssssaaaaaaaa(a3, a2, a1, a0,
                a3, a2, a1, a0,
                Lp[3] & m, Lp[2] & m, Lp[1] & m, Lp[0] & m);
            h = d3;
        }
    }

    /* one extra step at i = r absorbs the truncation creep */
    {
        nn_srcptr Lp = LP((slong) r);
        const int b = 26;

        v0 = MPN_RIGHT_SHIFT_LOW(p1, p0, b);
        v1 = MPN_RIGHT_SHIFT_LOW(p2, p1, b);
        v2 = MPN_RIGHT_SHIFT_LOW(p3, p2, b);
        v3 = MPN_RIGHT_SHIFT_LOW(UWORD(1), p3, b);
        sub_dddddmmmmmsssss(bw, e3, e2, e1, e0,
            UWORD(0), d3, d2, d1, d0,
            UWORD(0), v3, v2, v1, v0);
        m = ~bw;                /* accept iff no borrow */
        d0 = (d0 & bw) | (e0 & m);
        d1 = (d1 & bw) | (e1 & m);
        d2 = (d2 & bw) | (e2 & m);
        d3 = (d3 & bw) | (e3 & m);
        add_ssssaaaaaaaa(p3, p2, p1, p0,
            p3, p2, p1, p0,
            (v3) & m, (v2) & m, (v1) & m, (v0) & m);
        add_ssssaaaaaaaa(a3, a2, a1, a0,
            a3, a2, a1, a0,
            Lp[3] & m, Lp[2] & m, Lp[1] & m, Lp[0] & m);
    }

#undef LP

    /* t = D 2^(FLINT_BITS 4) / (X + P) */
    add_sssssaaaaaaaaaa(S[4], S[3], S[2], S[1], S[0],
        UWORD(1), x[3], x[2], x[1], x[0],
        UWORD(1), p3, p2, p1, p0);
    nd[0] = 0;
    nd[1] = 0;
    nd[2] = 0;
    nd[3] = 0;
    nd[4] = d0;
    nd[5] = d1;
    nd[6] = d2;
    nd[7] = d3;
    flint_mpn_zero(t, 4);
    if (d3 != 0 || d2 != 0 || d1 != 0 || d0 != 0)
        mpn_tdiv_qr(t, nd, 0, nd, 8, S, 5);

    _fixed_log1p_series_4(y, t);

    add_ssssaaaaaaaa(res[3], res[2], res[1], res[0],
        a3, a2, a1, a0,
        (y[3] << 1) | (y[2] >> (FLINT_BITS - 1)), (y[2] << 1) | (y[1] >> (FLINT_BITS - 1)), (y[1] << 1) | (y[0] >> (FLINT_BITS - 1)), y[0] << 1);
}


